import React, { useEffect, useState } from "react";
import { createClient } from "@supabase/supabase-js";

// Supabase bağlantı bilgilerin
const supabaseUrl = "https://cnakyamdydqxistdavfg.supabase.co";
const supabaseKey =
    "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImNuYWt5YW1keWRxeGlzdGRhdmZnIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NTM5NDIzNTEsImV4cCI6MjA2OTUxODM1MX0.mAVSru38H63peSy0iH6nDdJ0WBxBwQcoVJwYMy9UKBo";

const supabase = createClient(supabaseUrl, supabaseKey);

// İstenen kolon sırası
const columnOrder = [
    "PROJE ADI",
    "TALEP",
    "TEDARİK",
    "VERİLEMEYEN",
    "TED. %",
    "SPOT",
    "FİLO",
    "TESİSTE",
    "GELECEK",
    "YÜKLENDİ",
    "HEDEF ÜSTÜ SEFER",
    "HEDEF ALTI SEFER",
    "HEDEF SEFER",
    "HEDEFSİZ SEFER"
];

function App() {
    const [data, setData] = useState([]);

    useEffect(() => {
        async function fetchData() {
            const { data, error } = await supabase
                .from("toplu_sonuclar")
                .select("json_data, created_at")
                .order("created_at", { ascending: false })
                .limit(1); // Son eklenen veri alınır

            if (error) {
                console.error("Supabase veri çekme hatası:", error);
                return;
            }

            if (data && data.length > 0) {
                setData(data[0].json_data);
            }
        }

        fetchData();
    }, []);

    return (
        <div className="App">
            <h1>TEDARİK PERFORMANS RAPORU</h1>
            {data.length > 0 ? (
                <table border="1" style={{ borderCollapse: "collapse", width: "100%" }}>
                    <thead>
                        <tr>
                            {columnOrder.map((col) => (
                                <th key={col}>{col}</th>
                            ))}
                        </tr>
                    </thead>
                    <tbody>
                        {data.slice(1).map((row, idx) => (
                            <tr key={idx}>
                                {columnOrder.map((col, i) => (
                                    <td key={i}>{row[col]}</td>
                                ))}
                            </tr>
                        ))}
                    </tbody>
                </table>
            ) : (
                <p>Yükleniyor...</p>
            )}
        </div>
    );
}

export default App;
